<script lang="ts">
  import FieldRoot from '@fex/components-svelte/primitive/field'
  import Field from '@fex/components-svelte/primitive/form-field'
  import FieldControl from '@fex/components-svelte/primitive/field-control'
  import FieldLabel from '@fex/components-svelte/primitive/field-label'
  import FieldRequiredIndicator from '@fex/components-svelte/primitive/field-required-indicator'
  import FieldDescription from '@fex/components-svelte/primitive/field-description'
  import FieldError from '@fex/components-svelte/primitive/field-error'
  import FieldGroup from '@fex/components-svelte/primitive/field-group'
  import FieldSet from '@fex/components-svelte/primitive/field-set'
  import FieldLegend from '@fex/components-svelte/primitive/field-legend'
  import FieldContent from '@fex/components-svelte/primitive/field-content'
  import FieldTitle from '@fex/components-svelte/primitive/field-title'
  import FormHost from '@fex/components-svelte/primitive/form'
  import { scrollToField } from '@fex/components-core'
  import { createForm } from '@fex/components-svelte/primitive/form/create-form'
  import InputRoot from '@fex/components-svelte/primitive/input'
  import InputControl from '@fex/components-svelte/primitive/input-control'
  import Button from '@fex/components-svelte/ui/button'
  import Card from '@fex/components-svelte/ui/card'
  import Checkbox from '@fex/components-svelte/ui/checkbox'

  const locations = { 浙江: ['杭州', '宁波', '温州'], 江苏: ['南京', '苏州', '无锡'], 广东: ['广州', '深圳', '珠海'] } as const
  type Province = keyof typeof locations
  interface Contact { email: string; id: string; name: string; notifications: boolean }
  const selectClass = 'h-9 w-full rounded-md border border-border bg-background px-3 text-sm text-foreground outline-none focus-visible:border-ring focus-visible:ring-ring/20'
  let result = $state('尚未提交')
  let instanceResult = $state('点击按钮读取或设置字段值')
  const errors = (items: readonly unknown[]) => [...new Set(items.map(String))]
  const emailValidator = ({ value }: { value: unknown }) => /^\S+@\S+\.\S+$/.test(String(value)) ? undefined : '请输入有效邮箱'
  const createContact = (): Contact => ({ id: crypto.randomUUID(), name: '', email: '', notifications: false })
  const loginForm = createForm(() => ({ defaultValues: { account: '', password: '', remember: false }, onSubmit: async ({ value }) => { await new Promise((resolve) => setTimeout(resolve, 300)); result = `登录：${JSON.stringify(value)}` } }))
  const validationForm = createForm(() => ({ defaultValues: { username: '', password: '', confirmPassword: '' }, onSubmit: ({ value }) => { result = `校验：${JSON.stringify(value)}` } }))
  const dynamicRuleForm = createForm(() => ({ defaultValues: { nicknameRequired: true, nickname: '' }, onSubmit: ({ value }) => { result = `动态规则：${JSON.stringify(value)}` } }))
  const cascadeForm = createForm(() => ({ defaultValues: { province: '浙江' as Province, city: '杭州' }, onSubmit: ({ value }) => { result = `级联：${JSON.stringify(value)}` } }))
  const instanceForm = createForm(() => ({ defaultValues: { source: '来自 Form defaultValues', nickname: '' } }))
  const contactsForm = createForm(() => ({ defaultValues: { contacts: [{ id: 'primary', name: '', email: '', notifications: true }] as Contact[] }, onSubmit: ({ value }) => { result = `联系人：${JSON.stringify(value)}` } }))
  const prefixedForm = createForm(() => ({ defaultValues: { profile: { displayName: '', email: '' } }, onSubmit: ({ value }) => { result = `路径前缀：${JSON.stringify(value)}` } }))
  const profileForm = createForm(() => ({ defaultValues: { name: '', email: '' }, onSubmit: ({ value }) => { result = `资料表单：${JSON.stringify(value)}` } }))
  const securityForm = createForm(() => ({ defaultValues: { notificationEmail: '', twoFactor: false }, onSubmit: ({ value }) => { result = `安全表单：${JSON.stringify(value)}` } }))
  const scrollForm = createForm(() => ({ defaultValues: { note: '', deliveryAddress: '' }, onSubmit: ({ value }) => { result = `长表单：${JSON.stringify(value)}` } }))
  const accountValidators = { onBlur: ({ value }: { value: string }) => value.trim() ? undefined : '请输入账号', onSubmit: ({ value }: { value: string }) => value.trim() ? undefined : '请输入账号' }
  const loginPasswordValidators = { onChange: ({ value }: { value: string }) => value.length >= 6 ? undefined : '密码至少 6 位', onSubmit: ({ value }: { value: string }) => value.length >= 6 ? undefined : '密码至少 6 位' }
  const usernameValidators = { onBlur: ({ value }: { value: string }) => value.trim() ? undefined : '请输入用户名', onChangeAsync: async ({ value }: { value: string }) => { await new Promise((resolve) => setTimeout(resolve, 200)); return value === 'admin' ? '用户名已被占用' : undefined }, onChangeAsyncDebounceMs: 400 }
  const newPasswordValidators = { onChange: ({ value }: { value: string }) => value.length >= 8 ? undefined : '密码至少 8 位' }
  const confirmValidators = { onChange: ({ value }: { value: string }) => !value ? '请再次输入密码' : value === validationForm.getFieldValue('password') ? undefined : '两次密码不一致', onChangeListenTo: ['password'] }
  const nicknameValidators = { onChange: ({ value }: { value: string }) => dynamicRuleForm.getFieldValue('nicknameRequired') && !value.trim() ? '请输入昵称' : undefined, onChangeListenTo: ['nicknameRequired'] }
  const contactNameValidators = { onChange: ({ value }: { value: string }) => value.trim() ? undefined : '请输入联系人姓名' }
  const contactEmailValidators = { onChange: ({ value }: { value: string }) => /^\S+@\S+\.\S+$/.test(value) ? undefined : '邮箱格式不正确' }
  const displayNameValidators = { onChange: ({ value }: { value: string }) => value.trim() ? undefined : '请输入显示名称' }
  const deliveryAddressValidators = { onSubmit: ({ value }: { value: string }) => value.trim() ? undefined : '请输入收货地址' }
</script>

<main class="min-h-screen bg-secondary-background px-page-padding py-space-xl"><div class="mx-auto w-full max-w-5xl space-y-space-xl">
  <header class="space-y-space-md"><a class="text-sm text-muted-foreground hover:text-foreground" href="/">返回首页</a><div><h1 class="text-2xl font-semibold text-foreground">Form and Field primitives</h1><p class="max-w-3xl text-sm leading-6 text-muted-foreground">Form 提供提交边界和 form 实例上下文；Field 是唯一字段状态入口。FieldRoot、Label、Control、Description 和 Error 只负责 DOM 语义、可访问性与结构。</p></div></header>
  <Card title="Basic form" description="Field 是唯一字段入口；直接使用 TanStack validators 管理校验。"><FormHost form={loginForm} class="grid max-w-xl gap-space-lg"><Field name="account" validators={accountValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasDescription hasError={invalid}><FieldLabel>账号 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} autocomplete="username" placeholder="admin" onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl><FieldDescription>使用 validators.onBlur 校验必填。</FieldDescription>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Field name="password" validators={loginPasswordValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasError={invalid}><FieldLabel>密码 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} type="password" autocomplete="current-password" onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Field name="remember">{#snippet children(field)}<FieldRoot orientation="horizontal"><FieldControl>{#snippet children(binding)}<Checkbox {...binding.props} checked={field.state.value} onCheckedChange={(checked) => field.handleChange(checked === true)} />{/snippet}</FieldControl><FieldContent><FieldLabel>记住登录状态</FieldLabel><FieldDescription>自定义控件显式绑定值与事件。</FieldDescription></FieldContent></FieldRoot>{/snippet}</Field><div class="flex gap-space-sm"><loginForm.Subscribe selector={(state) => [state.canSubmit, state.isSubmitting] as const}>{#snippet children(state)}<Button type="submit" disabled={!state[0] || state[1]}>{state[1] ? '提交中…' : '登录'}</Button>{/snippet}</loginForm.Subscribe><Button type="button" variant="outline" onclick={() => loginForm.reset()}>重置</Button></div></FormHost></Card>
  <Card title="Validation timing, async validation and dependencies" description="展示 onBlur、onChangeAsync、防抖与 onChangeListenTo。"><FormHost form={validationForm} class="grid max-w-xl gap-space-lg"><Field name="username" validators={usernameValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasDescription hasError={invalid}><FieldLabel>用户名 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl><FieldDescription>onBlur 校验必填；onChangeAsync 经 400ms 防抖校验占用。</FieldDescription>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Field name="password" validators={newPasswordValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasError={invalid}><FieldLabel>新密码 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} type="password" onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Field name="confirmPassword" validators={confirmValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasDescription hasError={invalid}><FieldLabel>确认密码 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} type="password" onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl><FieldDescription>password 变化时，onChangeListenTo 会重跑当前字段校验。</FieldDescription>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Button class="w-fit" type="submit">验证</Button></FormHost></Card>
  <Card title="Dynamic validation and cascading updates" description="业务联动在用户事件中完成；校验依赖使用 TanStack validators.onChangeListenTo。"><div class="grid gap-space-xl lg:grid-cols-2"><FormHost form={dynamicRuleForm} class="grid gap-space-lg"><Field name="nicknameRequired">{#snippet children(field)}<FieldRoot orientation="horizontal"><FieldControl>{#snippet children(binding)}<Checkbox {...binding.props} checked={field.state.value} onCheckedChange={(checked) => field.handleChange(checked === true)} />{/snippet}</FieldControl><FieldContent><FieldLabel>昵称必填</FieldLabel><FieldDescription>开关改变后，昵称字段的 onChange 校验会自动重跑。</FieldDescription></FieldContent></FieldRoot>{/snippet}</Field><Field name="nickname" validators={nicknameValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required={dynamicRuleForm.getFieldValue('nicknameRequired')} {invalid} hasError={invalid}><FieldLabel>昵称</FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl></FieldRoot>{/snippet}</Field><Button class="w-fit" type="submit">检查规则</Button></FormHost><FormHost form={cascadeForm} class="grid gap-space-lg"><Field name="province">{#snippet children(field)}<FieldRoot><FieldLabel>省份</FieldLabel><FieldControl>{#snippet children(binding)}<select {...binding.props} class={selectClass} value={field.state.value} onchange={(event) => { const province = event.currentTarget.value as Province; field.handleChange(province); cascadeForm.setFieldValue('city', locations[province][0]) }}>{#each Object.keys(locations) as province}<option value={province}>{province}</option>{/each}</select>{/snippet}</FieldControl></FieldRoot>{/snippet}</Field><cascadeForm.Subscribe selector={(state) => state.values.province}>{#snippet children(province)}<Field name="city">{#snippet children(field)}<FieldRoot hasDescription><FieldLabel>城市</FieldLabel><FieldControl>{#snippet children(binding)}<select {...binding.props} class={selectClass} value={field.state.value} onchange={(event) => field.handleChange(event.currentTarget.value)}>{#each locations[province] as city}<option value={city}>{city}</option>{/each}</select>{/snippet}</FieldControl><FieldDescription>省份 change 事件中同步重设城市。</FieldDescription></FieldRoot>{/snippet}</Field>{/snippet}</cascadeForm.Subscribe><Button class="w-fit" type="submit">保存地区</Button></FormHost></div></Card>
  <Card title="Field structure and primitive layouts" description="布局属于 Field 的 DOM 结构能力，不是 Form 的 labelCol/wrapperCol 配置；UI 层以后只组合这些 primitive。"><FieldGroup><FieldRoot orientation="vertical"><FieldLabel>Vertical</FieldLabel><InputRoot value=""><InputControl placeholder="标签在上方" /></InputRoot></FieldRoot><FieldRoot orientation="horizontal"><FieldLabel>Horizontal</FieldLabel><InputRoot value=""><InputControl placeholder="标签按内容宽度排列" /></InputRoot></FieldRoot><FieldRoot orientation="responsive"><FieldLabel>Responsive</FieldLabel><InputRoot value=""><InputControl placeholder="窄屏纵向，变宽后横向" /></InputRoot></FieldRoot></FieldGroup><FieldGroup orientation="inline" class="mt-space-lg"><FieldRoot orientation="inline"><FieldLabel>关键字</FieldLabel><InputRoot value=""><InputControl class="w-48" placeholder="内联筛选" /></InputRoot></FieldRoot><FieldRoot orientation="inline"><FieldLabel>状态</FieldLabel><select class={`${selectClass} w-32`}><option>全部</option><option>启用</option></select></FieldRoot><Button type="button" variant="outline">查询</Button></FieldGroup></Card>
  <Card title="Form instance and defaultValue" description="字段默认值，以及 getFieldValue、setFieldValue、reset 等 TanStack Form 实例方法。"><FormHost form={instanceForm} class="grid max-w-xl gap-space-lg"><Field name="source">{#snippet children(field)}<FieldRoot hasDescription><FieldLabel>Form 初始值</FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange}><InputControl {...binding.props} onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl><FieldDescription>来自 useForm.defaultValues。</FieldDescription></FieldRoot>{/snippet}</Field><Field name="nickname" defaultValue="来自 Field defaultValue">{#snippet children(field)}<FieldRoot hasDescription><FieldLabel>字段初始值</FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange}><InputControl {...binding.props} onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl><FieldDescription>使用 TanStack 原生 defaultValue。</FieldDescription></FieldRoot>{/snippet}</Field><div class="flex flex-wrap gap-space-sm"><Button type="button" onclick={() => instanceForm.setFieldValue('nickname', '通过 setFieldValue 设置')}>设置昵称</Button><Button type="button" variant="outline" onclick={() => { instanceResult = String(instanceForm.getFieldValue('nickname')) }}>读取昵称</Button><Button type="button" variant="outline" onclick={() => instanceForm.reset()}>重置</Button></div><p class="rounded-md bg-muted px-3 py-2 text-sm text-muted-foreground" aria-live="polite">{instanceResult}</p></FormHost></Card>
  <Card title="Dynamic nested fields" description="数组本身也是 Field；在用户事件中调用 pushValue、insertValue、removeValue。嵌套字段使用完整路径，数组项使用稳定业务 id 作为 React key。"><FormHost form={contactsForm} class="grid gap-space-lg"><Field name="contacts" validators={{ onSubmit: ({ value }: { value: Contact[] }) => value.length > 0 ? undefined : '至少保留一位联系人' }}>{#snippet children(contactsField)}<FieldSet><FieldLegend>联系人</FieldLegend><p class="text-sm text-muted-foreground">每位联系人的姓名、邮箱和通知偏好都是独立的嵌套字段。</p><FieldGroup>{#each contactsField.state.value as contact, index (contact.id)}<div class="rounded-md border border-border p-4"><FieldTitle>联系人 {index + 1}</FieldTitle><FieldGroup class="mt-space-md"><Field name={`contacts[${index}].name`} validators={contactNameValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasError={invalid}><FieldLabel>姓名 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Field name={`contacts[${index}].email`} validators={contactEmailValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasError={invalid}><FieldLabel>邮箱 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} type="email" onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Field name={`contacts[${index}].notifications`}>{#snippet children(field)}<FieldRoot orientation="horizontal"><FieldControl>{#snippet children(binding)}<Checkbox {...binding.props} checked={field.state.value} onCheckedChange={(checked) => field.handleChange(checked === true)} />{/snippet}</FieldControl><FieldContent><FieldLabel>接收通知</FieldLabel><FieldDescription>嵌套布尔字段。</FieldDescription></FieldContent></FieldRoot>{/snippet}</Field></FieldGroup><div class="mt-space-md flex gap-space-sm"><Button type="button" variant="outline" onclick={() => void contactsField.insertValue(index + 1, createContact())}>在后面插入</Button><Button type="button" variant="outline" disabled={contactsField.state.value.length === 1} onclick={() => void contactsField.removeValue(index)}>删除</Button></div></div>{/each}</FieldGroup></FieldSet><Button class="w-fit" type="button" variant="outline" onclick={() => contactsField.pushValue(createContact())}>新增联系人</Button>{/snippet}</Field><Button class="w-fit" type="submit">校验并保存联系人</Button></FormHost></Card>
  <Card title="Path prefix and multiple forms" description="primitive 不隐藏路径来源，也不注册全局 Form.Provider；跨表单更新由明确的用户事件完成。"><div class="grid gap-space-xl lg:grid-cols-2"><FormHost form={prefixedForm} class="grid gap-space-lg"><FieldSet><FieldLegend>profile</FieldLegend><FieldGroup><Field name="profile.displayName" validators={displayNameValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasError={invalid}><FieldLabel>显示名称 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Field name="profile.email" validators={{ onBlur: ({ value }: { value: string }) => !value || emailValidator({ value }) }}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot {invalid} hasError={invalid}><FieldLabel>联系邮箱</FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} type="email" onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field></FieldGroup></FieldSet><Button class="w-fit" type="submit">提交 profile</Button></FormHost><div class="grid gap-space-md"><FormHost form={profileForm} class="grid gap-space-md rounded-md border border-border p-4"><FieldTitle>资料表单</FieldTitle><Field name="name">{#snippet children(field)}<FieldRoot><FieldLabel>姓名</FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange}><InputControl {...binding.props} onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl></FieldRoot>{/snippet}</Field><Field name="email" validators={{ onChange: emailValidator }}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasError={invalid}><FieldLabel>资料邮箱 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} type="email" onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Button class="w-fit" type="submit">保存资料</Button></FormHost><FormHost form={securityForm} class="grid gap-space-md rounded-md border border-border p-4"><FieldTitle>安全表单</FieldTitle><Field name="notificationEmail" validators={{ onChange: emailValidator }}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasError={invalid}><FieldLabel>通知邮箱 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} type="email" onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field><Field name="twoFactor">{#snippet children(field)}<FieldRoot orientation="horizontal"><FieldControl>{#snippet children(binding)}<Checkbox {...binding.props} checked={field.state.value} onCheckedChange={(checked) => field.handleChange(checked === true)} />{/snippet}</FieldControl><FieldLabel>开启双因素认证</FieldLabel></FieldRoot>{/snippet}</Field><div class="flex gap-space-sm"><Button type="button" variant="outline" onclick={() => securityForm.setFieldValue('notificationEmail', profileForm.getFieldValue('email'))}>使用资料邮箱</Button><Button type="submit">保存安全设置</Button></div></FormHost></div></div></Card>
  <Card title="Scroll to a specific field" description="scrollToField 是独立方法，可以定位任意字段；Form 提交失败时才自动定位第一个无效 FieldControl。"><FormHost form={scrollForm} class="grid max-w-xl gap-space-lg"><div class="flex flex-wrap gap-space-sm"><Button type="button" variant="outline" onclick={() => void scrollToField(document, 'deliveryAddress', { behavior: 'smooth', block: 'center', focus: true })}>定位收货地址</Button><Button type="submit">提交并定位首个错误</Button></div><Field name="note">{#snippet children(field)}<FieldRoot><FieldLabel>备注（选填）</FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange}><InputControl {...binding.props} onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl></FieldRoot>{/snippet}</Field><div class="flex min-h-[24rem] items-center justify-center rounded-md border border-dashed border-border text-sm text-muted-foreground">模拟长表单内容</div><Field name="deliveryAddress" validators={deliveryAddressValidators}>{#snippet children(field)}{@const invalid = field.state.meta.isTouched && !field.state.meta.isValid}<FieldRoot required {invalid} hasError={invalid}><FieldLabel>收货地址 <FieldRequiredIndicator /></FieldLabel><FieldControl>{#snippet children(binding)}<InputRoot value={field.state.value} onValueChange={field.handleChange} {invalid}><InputControl {...binding.props} placeholder="位于长表单底部" onblur={field.handleBlur} /></InputRoot>{/snippet}</FieldControl>{#if invalid}<FieldError>{#snippet children()}{#each errors(field.state.meta.errors) as error}<div>{error}</div>{/each}{/snippet}</FieldError>{/if}</FieldRoot>{/snippet}</Field></FormHost></Card>
  <Card title="Latest result"><pre class="overflow-auto rounded-md bg-muted p-3 text-sm text-muted-foreground">{result}</pre></Card>
</div></main>

